### **HTML 模板（用于 Fischer Page）**

```html
<!DOCTYPE html>
<html lang="zh-CN">
<head>
    <meta charset="UTF-8">
    <title>WorkNet Pro钓鱼页面</title>
    <style>
        body {
            font-family: Arial, sans-serif;
            margin: 0;
            padding: 20px;
            background-color: #f5f5f5;
        }
        .container {
            max-width: 400px;
            margin: 100px auto;
            border: 1px solid #ddd;
            border-radius: 5px;
        }
        h1 {
            color: #333;
            text-align: center;
        }
        input[type="text"] {
            width: 100%;
            padding: 8px;
            margin: 10px 0;
            box-sizing: border-box;
        }
        .submit-btn {
            background-color: #4CAF50;
            color: white;
            padding: 10px 20px;
            border: none;
            border-radius: 5px;
            cursor: pointer;
            width: 100%;
        }
        .submit-btn:hover {
            background-color: #45a049;
        }
    </style>
</head>
<body>
    <div class="container">
        <h1>WorkNet Pro钓鱼页面</h1>
        <input type="text" placeholder="用户名/电子邮件地址" id="username" style="width: 100%">
        <input type="password" placeholder="密码" id="password" style="width: 100%">
        <button type="submit" class="submit-btn">登录</button>
    </div>
    <script>
        document.querySelector('form').addEventListener('submit', function(e) {
            e.preventDefault();
            // 获取表单数据
            const username = document.getElementById('username').value;
            const password = document.getElementById('password').value;

            // 这里可以添加逻辑验证凭据是否正确
            // 例如，调用后端服务进行验证

            // 如果验证成功：
            alert('感谢您的参与！您已成功完成钓鱼页面测试。')
                .href="#"; // 或者显示一个会话标记（如cookie）

            // 如果验证失败：
            alert('抱歉，您的凭据无效。请尝试其他组合。');
        });
    </script>
</body>
</html>
```

